// ─── Challenges Card ──────────────────────────────────────────────────────────
const ChallengesCard = ({ onViewAll, onChallengeComplete }) => {
  const [checked,  setChecked]  = useState(loadChecked);
  const [particles,setParticles]= useState([]);
  const [popup,    setPopup]    = useState(null);
  const itemRefs = useRef({});

  // Re-sync from localStorage on tab focus
  useEffect(() => {
    const sync = () => setChecked(loadChecked());
    sync();
    window.addEventListener('focus', sync);
    return () => window.removeEventListener('focus', sync);
  }, []);

  const spawnParticles = useCallback((originEl, xp, coins, barEffects) => {
    const rect    = originEl.getBoundingClientRect();
    const originX = rect.left + rect.width  / 2;
    const originY = rect.top  + rect.height / 2;

    const getCenter = (el) => {
      if (!el) return { x: window.innerWidth / 2, y: 60 };
      const r = el.getBoundingClientRect();
      return { x: r.left + r.width / 2, y: r.top + r.height / 2 };
    };

    const xpPos   = getCenter(document.querySelector('.xp-chip'));
    const coinPos = getCenter(document.querySelector('.coins-chip'));

    const now = Date.now();
    const newParticles = [];

    // XP stars → top bar xp chip
    for (let i = 0; i < 6; i++) {
      newParticles.push({
        id:`${now}-xp-${i}`, x:originX, y:originY,
        tx:xpPos.x-originX+(Math.random()-0.5)*20,
        ty:xpPos.y-originY,
        icon:'/star.png', color:'#34d399', delay:i*0.07,
      });
    }
    // Coin particles → top bar coins chip
    for (let i = 0; i < 6; i++) {
      newParticles.push({
        id:`${now}-coin-${i}`, x:originX, y:originY,
        tx:coinPos.x-originX+(Math.random()-0.5)*20,
        ty:coinPos.y-originY,
        icon:'/profit.png', color:'#fbbf24', delay:0.1+i*0.07,
      });
    }
    // Stat particles → fly to the stat bars on the dashboard avatar card
    if (barEffects) {
      Object.entries(barEffects).forEach(([statKey, statVal], idx) => {
        const meta = statMeta[statKey];
        if (!meta) return;
        const targetEl = document.querySelector(`.progress-fill.${statKey === 'hp' ? 'red' : statKey === 'energy' ? 'blue' : 'green'}`);
        const targetPos = getCenter(targetEl);
        for (let i = 0; i < 5; i++) {
          newParticles.push({
            id:`${now}-stat-${statKey}-${i}`, x:originX, y:originY,
            tx:targetPos.x-originX+(Math.random()-0.5)*30,
            ty:targetPos.y-originY,
            icon:meta.icon, color:meta.color, delay:0.15+idx*0.1+i*0.08,
          });
        }
      });
    }

    setParticles(prev => [...prev, ...newParticles]);
    setTimeout(() => setParticles(prev => prev.filter(p => !newParticles.find(n => n.id === p.id))), 3500);

    // Pulse the stat bars when particles land (~1.6s)
    if (barEffects) {
      Object.keys(barEffects).forEach(statKey => {
        setTimeout(() => {
          const cls = statKey==='hp'?'red':statKey==='energy'?'blue':'green';
          const el  = document.querySelector(`.progress-fill.${cls}`);
          if (el) {
            el.classList.add('db-bar-pulse');
            setTimeout(() => el.classList.remove('db-bar-pulse'), 1000);
          }
        }, 1650);
      });
    }
  }, []);

  const toggle = (i) => {
    if (checked[i]) return;
    const next = { ...checked, [i]: true };
    setChecked(next);
    saveChecked(next);

    const c   = DAILY[i];
    const xpMatch = c.reward.match(/(\d+)\s*XP/);
    const xp  = xpMatch ? parseInt(xpMatch[1]) : 0;
    const coins = Math.max(5, Math.round(xp * 0.2));

    // Build popup stats list
    const stats = c.barEffects
      ? Object.entries(c.barEffects).map(([k,v]) => ({ ...statMeta[k], val:v })).filter(s=>s.icon)
      : [];

    setPopup({ xp, coins, stats });
    setTimeout(() => setPopup(null), 2800);

    const el = itemRefs.current[i];
    if (el) spawnParticles(el, xp, coins, c.barEffects);

    if (onChallengeComplete) onChallengeComplete(xp, coins, c.barEffects || null);
  };

  const done = Object.values(checked).filter(Boolean).length;

  return (
    <>
      {/* Particles rendered at document level */}
      <div className="db-particles-root">
        {particles.map(p => <FlyingParticle key={p.id} particle={p}/>)}
      </div>

      {/* Reward popup */}
      <RewardPopup popup={popup}/>

      <div className="bio-card-inner challenges-summary-inner">
        <div className="bio-card-top">
          <span className="bio-icon">🏆</span>
          <div>
            <div className="bio-title">Challenges</div>
            <div className="bio-subtitle">{done}/{DAILY.length} daily done</div>
          </div>
          <button className="view-all-btn" onClick={onViewAll}>View All →</button>
        </div>

        <div className="ch-section-label">DAILY</div>
        <div className="ch-list">
          {DAILY.slice(0,3).map((c,i) => (
            <div
              key={i}
              ref={el => itemRefs.current[i] = el}
              className={`ch-row ${checked[i]?'ch-done':''}`}
            >
              <div className={`ch-check ${checked[i]?'checked':''}`} onClick={() => toggle(i)}>
                {checked[i] && '✓'}
              </div>
              <span className="ch-title">{c.title}</span>
              <span className="ch-reward">🪙 {c.reward}</span>
            </div>
          ))}
        </div>

        <div className="ch-section-label" style={{marginTop:'0.5rem'}}>WEEKLY</div>
        <div className="ch-list">
          {WEEKLY.slice(0,2).map((c,i) => (
            <div key={i} className="ch-weekly-row">
              <div className="ch-weekly-top">
                <span className="ch-title">{c.title}</span>
                <span className="ch-reward">⚡ {c.reward}</span>
              </div>
              <div className="ch-weekly-bar">
                <div className="ch-weekly-fill" style={{width:`${c.progress}%`}}/>
              </div>
            </div>
          ))}
        </div>
      </div>
    </>
  );
};

