        <div className="card small-card bio-card" data-testid="heart-rate-card"><HeartRateCard/></div>
        <div className="card small-card bio-card" data-testid="sleep-card"><SleepCard/></div>
        <div className="card small-card bio-card" data-testid="steps-card"><StepsCard/></div>
        <div className="card small-card bio-card" data-testid="calories-card"><CaloriesCard/></div>
        <div className="card medium-card bio-card" data-testid="challenges-summary-card">
          <ChallengesCard
            onViewAll={() => navigate('/challenges')}
            onChallengeComplete={onChallengeComplete}
          />
        </div>
        <div className="card medium-card bio-card" data-testid="stress-card"><StressCard/></div>

        {/* Action buttons */}
        <button className="dashboard-action-btn doctor-btn"  onClick={() => setShowDoctor(true)}>👨‍⚕️ View Doctor</button>
        <button className="dashboard-action-btn sync-btn">🔗 Sync Device</button>
        <button className="dashboard-action-btn chatbot-btn" onClick={() => navigate('/chatbot')}>🤖 Chatbot</button>
      </div>

      {showDoctor && <ViewDoctorModal onClose={() => setShowDoctor(false)}/>}
    </div>
  );
};

export default Dashboard;
